import React, { useState, useEffect } from 'react';
import { Card, Table, Badge, Button, Spinner, Modal, Form } from 'react-bootstrap';
import axios from 'axios';

function OrdersList() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showStatus, setShowStatus] = useState(false);
  const [selectedOrder, setSelectedOrder] = useState(null);
  const [newStatus, setNewStatus] = useState('');

  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user') || '{}');
  const canManage = user.role === 'Admin' || user.role === 'Manager';

  useEffect(() => { loadOrders(); }, []);

  const loadOrders = async () => {
    try {
      const response = await axios.get('http://localhost:5051/api/Orders', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setOrders(response.data);
    } catch (err) {
      setError('Ошибка загрузки заказов');
    }
    setLoading(false);
  };

  const deleteOrder = async (orderId) => {
    if (!window.confirm('Удалить заказ? Товары вернутся на склад.')) return;
    try {
      await axios.delete(`http://localhost:5051/api/Orders/${orderId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      loadOrders();
    } catch (err) {
      alert('Ошибка удаления заказа');
    }
  };

  const updateStatus = async () => {
    try {
      await axios.put(`http://localhost:5051/api/Orders/${selectedOrder}/status`,
        { status: newStatus },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setShowStatus(false);
      loadOrders();
    } catch (err) {
      alert('Ошибка обновления статуса');
    }
  };

  const printOrder = async (orderId) => {
    try {
      const response = await axios.get(`http://localhost:5051/api/Orders/${orderId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      const order = response.data;
      const printWindow = window.open('', '_blank');
      
      printWindow.document.write(`
        <html>
          <head>
            <title>Заказ ${order.orderNumber}</title>
            <style>
              body { font-family: Arial, sans-serif; padding: 30px; color: #1a1a1a; }
              .header { text-align: center; margin-bottom: 30px; border-bottom: 3px solid #8B0000; padding-bottom: 20px; }
              .header h1 { color: #8B0000; margin: 0; font-size: 28px; }
              .header h2 { margin: 10px 0 5px; font-size: 20px; }
              .header p { color: #666; margin: 5px 0; }
              .info { margin-bottom: 25px; }
              .info strong { color: #333; }
              table { width: 100%; border-collapse: collapse; margin: 20px 0; }
              th { background: #1a1a1a; color: white; padding: 12px; text-align: left; font-weight: 600; }
              td { padding: 10px 12px; border-bottom: 1px solid #e0e0e0; }
              .total { text-align: right; font-size: 1.3em; font-weight: bold; margin-top: 20px; padding: 15px; background: #f5f5f5; border-radius: 8px; }
              @media print { button { display: none; } }
            </style>
          </head>
          <body>
            <div class="header">
              <h1>🚗 AUTOPARTS</h1>
              <h2>Заказ №${order.orderNumber}</h2>
              <p>Дата: ${new Date(order.orderDate).toLocaleDateString('ru-RU', {day: 'numeric', month: 'long', year: 'numeric'})}</p>
            </div>
            
            <div class="info">
              <strong>Клиент:</strong> ${order.customer.fullName}<br>
              <strong>Телефон:</strong> ${order.customer.phone}<br>
              <strong>Автомобиль:</strong> ${order.customer.carModel || 'Не указано'}
            </div>
            
            <table>
              <thead>
                <tr>
                  <th>Артикул</th>
                  <th>Наименование</th>
                  <th>Бренд</th>
                  <th>Кол-во</th>
                  <th>Цена</th>
                  <th>Сумма</th>
                </tr>
              </thead>
              <tbody>
                ${order.items.map(item => `
                  <tr>
                    <td>${item.partArticle}</td>
                    <td>${item.partName}</td>
                    <td>${item.partBrand || '-'}</td>
                    <td>${item.quantity}</td>
                    <td>${item.priceAtOrder.toFixed(2)} ₽</td>
                    <td>${item.total.toFixed(2)} ₽</td>
                  </tr>
                `).join('')}
              </tbody>
            </table>
            
            <div class="total">
              Итого: ${order.totalAmount.toFixed(2)} ₽
            </div>
          </body>
        </html>
      `);
      
      printWindow.document.close();
      printWindow.print();
    } catch (err) {
      alert('Ошибка загрузки заказа');
    }
  };

  const getStatusBadge = (status) => {
    if (status === 'New') {
      return <span style={{ background: '#f0f0f0', color: '#8B0000', border: '1px solid #8B0000', padding: '5px 14px', borderRadius: 20, fontWeight: 600, fontSize: '0.8rem', display: 'inline-block' }}>🆕 Новый</span>;
    }
    if (status === 'Paid') {
      return <span style={{ background: '#e6f5e6', color: '#1a6b1a', padding: '5px 14px', borderRadius: 20, fontWeight: 600, fontSize: '0.8rem', display: 'inline-block' }}>💰 Оплачен</span>;
    }
    if (status === 'Shipped') {
      return <span style={{ background: '#f5f0e6', color: '#8B6B00', padding: '5px 14px', borderRadius: 20, fontWeight: 600, fontSize: '0.8rem', display: 'inline-block' }}>📦 Отгружен</span>;
    }
    if (status === 'Cancelled') {
      return <span style={{ background: '#e8e8e8', color: '#666', padding: '5px 14px', borderRadius: 20, fontWeight: 600, fontSize: '0.8rem', display: 'inline-block' }}>❌ Отменен</span>;
    }
    return <span style={{ background: '#e6f5e6', color: '#1a6b1a', padding: '5px 14px', borderRadius: 20, fontWeight: 600, fontSize: '0.8rem', display: 'inline-block' }}>✅ Завершен</span>;
  };

  if (loading) return (
    <div className="text-center" style={{ padding: 80 }}>
      <Spinner animation="border" style={{ color: '#8B0000', width: 48, height: 48 }} />
      <p style={{ marginTop: 16, color: '#888', fontWeight: 500 }}>Загрузка заказов...</p>
    </div>
  );

  if (error) return (
    <div style={{ background: '#f8d7da', color: '#721c24', padding: 16, borderRadius: 12, fontWeight: 500 }}>{error}</div>
  );

  return (
    <div>
      <h2 style={{ fontWeight: 700, color: '#1a1a1a', marginBottom: 24 }}>
        <span style={{ marginRight: 10 }}>📋</span>
        Заказы
        {orders.length > 0 && (
          <Badge style={{ background: '#8B0000', marginLeft: 12, fontSize: '0.8rem', padding: '6px 14px', borderRadius: 20, fontWeight: 500, color: 'white' }}>
            {orders.length}
          </Badge>
        )}
      </h2>
      
      <Card style={{ borderRadius: 16, border: '1px solid #e0e0e0', boxShadow: '0 2px 12px rgba(0,0,0,0.06)', overflow: 'hidden' }}>
        <Card.Body style={{ padding: 0 }}>
          <div style={{ overflowX: 'auto' }}>
            <Table hover style={{ marginBottom: 0 }}>
              <thead>
                <tr style={{ background: 'linear-gradient(135deg, #1a1a1a 0%, #2d2d2d 100%)' }}>
                  <th style={{ padding: '16px 18px', color: 'white', fontWeight: 600, fontSize: '0.85rem', border: 'none' }}>Номер заказа</th>
                  <th style={{ padding: '16px 18px', color: 'white', fontWeight: 600, fontSize: '0.85rem', border: 'none' }}>Клиент</th>
                  <th style={{ padding: '16px 18px', color: 'white', fontWeight: 600, fontSize: '0.85rem', border: 'none' }}>Дата</th>
                  <th style={{ padding: '16px 18px', color: 'white', fontWeight: 600, fontSize: '0.85rem', border: 'none', textAlign: 'right' }}>Сумма</th>
                  <th style={{ padding: '16px 18px', color: 'white', fontWeight: 600, fontSize: '0.85rem', border: 'none', textAlign: 'center' }}>Позиций</th>
                  <th style={{ padding: '16px 18px', color: 'white', fontWeight: 600, fontSize: '0.85rem', border: 'none' }}>Статус</th>
                  <th style={{ padding: '16px 18px', color: 'white', fontWeight: 600, fontSize: '0.85rem', border: 'none', textAlign: 'center' }}>Действия</th>
                </tr>
              </thead>
              <tbody>
                {orders.map((order, index) => (
                  <tr key={order.id} style={{ background: index % 2 === 0 ? 'white' : '#fafafa', transition: 'all 0.2s ease' }}
                    onMouseOver={(e) => e.currentTarget.style.background = '#f0f0f0'}
                    onMouseOut={(e) => e.currentTarget.style.background = index % 2 === 0 ? 'white' : '#fafafa'}
                  >
                    <td style={{ padding: '16px 18px', fontWeight: 600, color: '#8B0000' }}>{order.orderNumber}</td>
                    <td style={{ padding: '16px 18px', fontWeight: 500, color: '#1a1a1a' }}>{order.customerName}</td>
                    <td style={{ padding: '16px 18px', color: '#888', fontSize: '0.9rem' }}>
                      {new Date(order.orderDate).toLocaleDateString('ru-RU', { day: 'numeric', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' })}
                    </td>
                    <td style={{ padding: '16px 18px', fontWeight: 700, textAlign: 'right', fontSize: '1rem', color: '#1a1a1a' }}>{order.totalAmount.toFixed(2)} ₽</td>
                    <td style={{ padding: '16px 18px', textAlign: 'center', color: '#888' }}>{order.itemsCount}</td>
                    <td style={{ padding: '16px 18px' }}>
                      {canManage ? (
                        <span style={{ cursor: 'pointer' }} onClick={() => { setSelectedOrder(order.id); setNewStatus(order.status); setShowStatus(true); }}>
                          {getStatusBadge(order.status)}
                        </span>
                      ) : getStatusBadge(order.status)}
                    </td>
                    <td style={{ padding: '16px 18px', textAlign: 'center' }}>
                      <Button variant="link" size="sm" onClick={() => printOrder(order.id)}
                        style={{ background: '#f5f5f5', borderRadius: 8, padding: '8px 14px', color: '#888', textDecoration: 'none', transition: 'all 0.2s ease', fontSize: '1.1rem' }}
                        onMouseOver={(e) => { e.target.style.background = '#8B0000'; e.target.style.color = 'white'; e.target.style.transform = 'scale(1.1)'; }}
                        onMouseOut={(e) => { e.target.style.background = '#f5f5f5'; e.target.style.color = '#888'; e.target.style.transform = 'scale(1)'; }}
                        title="Печать заказа"
                      >🖨</Button>
                      {canManage && (
                        <Button variant="link" size="sm" onClick={() => deleteOrder(order.id)}
                          style={{ background: '#fff5f5', borderRadius: 8, padding: '8px 14px', color: '#dc3545', textDecoration: 'none', transition: 'all 0.2s ease', fontSize: '1.1rem', marginLeft: 4 }}
                          onMouseOver={(e) => { e.target.style.background = '#dc3545'; e.target.style.color = 'white'; }}
                          onMouseOut={(e) => { e.target.style.background = '#fff5f5'; e.target.style.color = '#dc3545'; }}
                          title="Удалить заказ"
                        >🗑</Button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </Table>
          </div>
          
          {orders.length === 0 && (
            <div style={{ textAlign: 'center', padding: 60, color: '#aaa' }}>
              <div style={{ fontSize: '3rem', marginBottom: 16 }}>📋</div>
              <p style={{ fontWeight: 500, fontSize: '1.1rem', marginBottom: 4 }}>Заказов пока нет</p>
              <small>Создайте заказ в разделе поиска запчастей</small>
            </div>
          )}
        </Card.Body>
      </Card>

      {/* Модальное окно смены статуса */}
      <Modal show={showStatus} onHide={() => setShowStatus(false)} centered>
        <Modal.Header closeButton style={{ background: 'linear-gradient(135deg, #1a1a1a 0%, #2d2d2d 100%)', color: 'white', borderBottom: '3px solid #8B0000' }}>
          <Modal.Title style={{ fontWeight: 700 }}>Изменить статус заказа</Modal.Title>
        </Modal.Header>
        <Modal.Body style={{ padding: 24 }}>
          <Form.Select value={newStatus} onChange={(e) => setNewStatus(e.target.value)} style={{ borderRadius: 10, padding: 12, fontSize: '1rem' }}>
            <option value="New">🆕 Новый</option>
            <option value="Paid">💰 Оплачен</option>
            <option value="Shipped">📦 Отгружен</option>
            <option value="Completed">✅ Завершен</option>
            <option value="Cancelled">❌ Отменен</option>
          </Form.Select>
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={() => setShowStatus(false)} style={{ borderRadius: 8 }}>Отмена</Button>
          <Button onClick={updateStatus} style={{ background: '#8B0000', border: 'none', borderRadius: 8, fontWeight: 600 }}>Сохранить</Button>
        </Modal.Footer>
      </Modal>
    </div>
  );
}

export default OrdersList;
